#include <bits/stdc++.h>
using namespace std;
#define ll long long
const int N=50005;
int n,k,s[N],f[N][25],dep[N],mx;
vector<int> g[N];
void dfs(int x,int fa)
{
	dep[x]=dep[fa]+1;
	f[x][0]=fa;
	for(int i=0;i<g[x].size();i++)
	{
		int to=g[x][i];
		if(to==fa) continue;
		dfs(to,x);
	}
}
void dfs2(int u)
{
	for(int i=0;i<g[u].size();i++)
	{
		int v=g[u][i];
		if(v==f[u][0]) continue;
		dfs2(v);
		s[u]+=s[v];
	}
	mx=max(mx,s[u]);
}
int lca(int x,int y)
{
	if(dep[y]<dep[x]) swap(x,y);
	int k=log2(dep[y])+1;
	for(int i=k;i>=0;i--)
	{
		if((dep[y]-(1<<i))>=dep[x]) y=f[y][i];
	}
	if(x==y) return x;
	for(int i=k;i>=0;i--)
	{
		if(f[x][i]&&f[x][i]!=f[y][i])
		{
			x=f[x][i];
			y=f[y][i];
		}
	}
	return f[x][0];
}
int main()
{
	cin>>n>>k;
	for(int i=1;i<n;i++)
	{
		int x,y;
		cin>>x>>y;
		g[x].push_back(y);
		g[y].push_back(x);
	}
	dfs(1,0);
	for(int j=1;(1<<j)<=n;j++)
	{
		for(int i=1;i<=n;i++)
		{
			f[i][j]=f[f[i][j-1]][j-1];
		}
	}
	while(k--)
	{
		int x,y;
		cin>>x>>y;
		s[x]++;
		s[y]++;
		int lc=lca(x,y);
		s[lc]--;
		s[f[lc][0]]--;
	}
	dfs2(1);
	cout<<mx;
	return 0;
}
